INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-29a002de-moex-00161', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '設甲於民國103年7月間死亡，甲有繼承人為乙、丙。甲留有數筆債務與存款、動產；甲立有遺 囑為遺贈。下列敘述，何者錯誤？', '["乙、丙在法院依公示催告程序公告，命甲之債權人於一定期限內報明其債權之期限內，不得對 於甲之任何債權人償還債務", "乙、丙中之一人如陳報遺產清冊，其他繼承人視為已陳報", "乙、丙開具遺產清冊陳報法院時，法院應同時指定會同開具財產清冊之人", "乙、丙非依規定償還債務後，不得向受遺贈人交付遺贈"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00162', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-110-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲、乙兩人正在競爭一份工作，這份工作需要持有有效駕照。甲為了讓
乙失去競爭機會，計畫讓乙因犯罪而被吊銷駕照。甲因此邀請乙外出用
餐，並於乙所飲用無酒精飲料內偷偷加入麻醉藥品。餐後，甲告訴乙，
剛聽說乙兒子發生意外事故，乙太太心急如焚，希望他立刻回家。乙在
未加確認事實下，立即開車回家，途中，因精神恍惚撞上路人 A，導致
A當場死亡。試問甲、乙行為依刑法如何論處？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "cbafc51b7589", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0711", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00163', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-110-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲、乙、丙相約到酒店慶生，並共同邀請已經喝不少酒之 A一起跳舞。
四人開始跳舞後不久，A 突然倒在甲身上。三人以為 A 是不勝酒力睡
著，趁機接續對當時表情就像睡著般之 A實施性侵入行為。後經鑑定，
在 A倒在甲身上當時就已經因心肌梗塞猝死。試問甲、乙、丙行為依刑
法如何論處？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "cbafc51b7589", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0711", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00164', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-110-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲在政府持股占 60%之 A 股份有限公司擔任辦公室資訊相關設備採購
業務。甲透過中間人乙傳話給 B公司負責人丙，表示如果願意與他合作，
他會提供協助，若不合作，他會讓 B公司永遠無法得到 A公司任何採購
標案。經過考慮，丙決定與甲合作。在 2005年至 2016年期間，甲於其
承辦之政府採購法採購程序，數次提供給 B公司投標相關資訊，使之順
利取得標案。每次丙均於透過乙交付一定金額，以作為取得標案之回報。
試問甲、乙、丙行為依刑法如何論處？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "cbafc51b7589", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0711", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00165', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-110-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲與乙在共同吸食安非他命時，甲因不耐其 6個月大兒子 A哭鬧，用力
搖晃導致 A摔落地面死亡。在旁目睹整個過程之乙受甲之託，以垃圾袋
包裹 A屍體掩埋於某墓園。甲始終良心不安而於事發後之第 7年自首。
偵查中，乙以證人身分具結後證述：「案發當日甲幫 A 洗澡，不慎讓 A
滑出澡盆摔死。」又針對檢察官所提「甲是否有吸食毒品」問題時，乙
答以：「不知道」。試問甲、乙行為依刑法如何論處？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "cbafc51b7589", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0711", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00166', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-110-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '甲將乙列為被告，起訴請求該管法院判決命乙應給付甲新臺幣（下同）
100 萬元，其陳述之事實及理由略為：乙於民國 110 年 5 月 10日駕駛小
客車與甲發生車禍，造成甲之名貴跑車毀損，支出維修費用 100萬元，
然乙卻一再拒絕賠償，為此提起訴訟，並聲明甲之友人丙為證人，以證
明該跑車確遭乙撞毀之事實；乙則請求駁回原告之訴，並抗辯甲、乙二
車相撞係因甲超速肇事。試問受訴法院應行何種訴訟程序？是否應即傳
喚丙以進行證據調查？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "5bab3309fc20", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0710", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00167', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-110-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '甲將乙列為被告，起訴請求該管法院判決命乙應負連帶保證人責任，給
付甲新臺幣（下同）200 萬元。其理由略為：丙於民國 108 年 3 月 1 日
向甲借款 200 萬元，約定還款日期為 110 年 2 月 28 日，並由乙為連帶
保證人，迄今仍未清償。於第二審程序中，甲追加丙為共同被告，試問
第二審法院應否許可追加丙為共同被告？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "5bab3309fc20", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0710", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00168', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-110-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '甲、乙二人基於犯意聯絡，共同販賣第三級毒品，經警查獲移送檢察官
偵辦，偵查終結後，檢察官對甲、乙二人，於同一訴訟程序依法提起公
訴，審判中法院依刑事訴訟法第 287 條之 1、第 287 條之 2 規定裁定程
序分離，在甲之案件審理中，乙被以證人身分傳喚到庭，依法定調查程
序對乙進行具結、詰問等程序，辯論終結後，法院僅依乙以證人身分到
庭陳述不利於甲之證言，為有罪判決之依據。試論法院之判決是否合
法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "5bab3309fc20", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0710", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00169', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-110-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '乙涉犯毒品罪嫌，被檢察官先以施用第二級毒品之被告身分訊問，期間
轉換以證人身分訊問，逕行告以具結之義務及偽證之處罰並命朗讀結文
後具結而為供述其係向甲購買毒品，偵查終結後，檢察官對甲以販賣毒
品罪嫌提起公訴。試論審判中被告甲，是否得主張因檢察官違反程序規
定未履行告知義務，乙於偵查中以證人身分所作之證言無證據能力？
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "5bab3309fc20", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0710", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00170', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-110-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'essay', '張三有子甲與女兒乙各一人。張三於罹癌入院後欲將所持有之 A地予以
出售，故簽署授權書，載明授權兒子甲代為出售A地，包含從契約訂定
到登記等事宜之各階段處理權及代理權。後來張三因癌症惡化於A地買
賣契約簽訂時，已經有意識狀態不清之情形，甲持其張三簽名之授權書，
與丙簽訂 A地買賣契約價金約定為 740萬元，並已給付由乙保管，由丙
依法辦理登記而於辦竣 A地登記前，張三因癌症過世。於張三死亡前，
均未曾受監護之宣告。
張三女兒乙認為張三授權甲之際已經病情嚴重而意識不清，主張該買賣
契約未有合法授權，故甲為無權代理，買賣契約無效，並主張甲保管 740
萬之行為侵害其財產繼承權，是否有理？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0704", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL)
